import{_ as a,o as r,c as t,O as d}from"./chunks/framework.4d49dab2.js";const u=JSON.parse('{"title":"Grid 布局","description":"","frontmatter":{},"headers":[],"relativePath":"css/grid.md","filePath":"css/grid.md","lastUpdated":1775463810000}'),i={name:"css/grid.md"};function o(s,e,l,c,n,p){return r(),t("div",null,[...e[0]||(e[0]=[d('<h1 id="grid-布局" tabindex="-1">Grid 布局 <a class="header-anchor" href="#grid-布局" aria-label="Permalink to &quot;Grid 布局&quot;">​</a></h1><p>网格是水平和垂直线段的集合，它们创建了一个模式，我们可以根据该模式来排列元素，使我们的元素不会在页面之间跳动或改变宽度，从而在我们的网站上提供更大的一致性。</p><p>在确定了设计所需的网格后，我们可以使用 CSS 网格布局来创建它。CSS 网格布局是 Web 的一个二维布局系统。它允许您将内容组织成行和列，并提供许多功能来简化复杂布局的创建。</p><h2 id="基础概念" tabindex="-1">基础概念 <a class="header-anchor" href="#基础概念" aria-label="Permalink to &quot;基础概念&quot;">​</a></h2><p>要将容器元素定义为网格，我们可以使用 <code>display: grid grid-template-columns</code> 和 <code>grid-template-rows</code> 设置列大小和行大小，然后使用 <code>grid-column</code> 和 <code>grid-row</code> 将其子元素放入网格中。</p><p>与 Flexbox 类似，网格项的源顺序无关紧要。您的 CSS 可以按任何顺序放置它们，这使得使用媒体查询重新排列网格变得非常容易。</p><p>想象一下，定义整个页面的布局，然后完全重新排列它以适应不同的屏幕宽度，所有这些都只需要几行 CSS。Grid 是有史以来最强大的 CSS 模块之一。</p><h2 id="网格术语" tabindex="-1">网格术语 <a class="header-anchor" href="#网格术语" aria-label="Permalink to &quot;网格术语&quot;">​</a></h2><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="https://mdn.org.cn/en-US/docs/Learn/CSS/CSS_layout/Grids" target="_blank" rel="noreferrer">网格布局 - 学习 Web 开发 | MDN - MDN 文档</a></li><li><a href="https://css-tricks.com/snippets/css/complete-guide-grid/" target="_blank" rel="noreferrer">CSS Grid Layout Guide | CSS-Tricks</a></li></ul>',10)])])}const S=a(i,[["render",o]]);export{u as __pageData,S as default};
